92	// ExecutionCleanupLivenessProbe decides whether a cleanup candidate should be
93	// preserved because it is still live.
94	type ExecutionCleanupLivenessProbe interface {
95		IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string)
96	}
97	
98	// defaultExecutionCleanupLivenessProbe preserves preserved metadata, a temp
99	// execution directory referenced by the live run-state file, or a candidate
100	// with an unexpired liveness marker. Tests can override the probe to model
101	// more specific host behavior.
102	type defaultExecutionCleanupLivenessProbe struct{}
103	
104	func (defaultExecutionCleanupLivenessProbe) IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string) {
105		if meta.Preserved {
106			return true, "preserved metadata"
107		}
108		if runState != nil {
109			if meta.WorktreePath != "" && filepath.Clean(runState.WorktreePath) == filepath.Clean(meta.WorktreePath) {
110				return true, "matched live run-state"
111			}
112			if meta.AttemptID != "" && runState.AttemptID == meta.AttemptID {
113				return true, "matched live run-state"
114			}
115		}
116		if meta.Liveness != nil {
117			if !meta.Liveness.ExpiresAt.IsZero() && now.Before(meta.Liveness.ExpiresAt) {
118				return true, "unexpired liveness"
119			}
120			if !meta.Liveness.RefreshedAt.IsZero() && now.Sub(meta.Liveness.RefreshedAt) <= 2*time.Minute {
121				return true, "fresh liveness"
122			}
123		}
124		return false, "stale liveness"
125	}
